var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"으으…….","JPN":"うう……","ENG":"Ugh...","TWN":"呃呃……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"노동자의 금품을 갈취하는 게 어디 있나! 악덕사장은 반성하라!","JPN":"労働者の金品を取り上げるなんて、悪徳社長は反省すべきだ！","ENG":"How can you rob innocent laborers of their goods?! You should be ashamed of yourself!","TWN":"哪裡有搶奪員工財物的道理！惡老闆給我反省吧！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"GAP_SILVER_NULL_NULL","text":{"KOREA":"따지고 보면 이건 원래 내 물건이다만…?","JPN":"だがこれは、元々私のモノなんだが……？","ENG":"I mean, this was technically my property all along…?","TWN":"嚴格來說，這本來就是我的東西……?"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"GAP_SILVER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"이 사달이 날 때 동안 가만히 있었으면서 무슨 소리예요? 고생이란 고생은 다 시켜놓고!","JPN":"こんな事態になるまで、ただ見ていたくせに、今更何を言っているんですか？　それを手に入れるために苦労したのは私たちなんですよ！","ENG":"How can you say that when you did nothing up until now? Do you know what I had to go through to get here?!","TWN":"事情發生的時候你一直在旁邊看著，現在在說什麼呢？我都已經受盡了苦頭！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GAP_SILVER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"GAP_SILVER_NULL_NULL","text":{"KOREA":"가만히라니! 세상을 지키는 이의 외로운 실정을 자네가 아는가?","JPN":"私が何もしなかっただと！？　世界を守る者の孤独を君は知らない！","ENG":"\\"Nothing\\"? Do you know how lonely it is to be the one who has to protect the world?","TWN":"什、什麼叫在旁邊看著！你知道守護世界的人有多麼孤獨嗎！？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GAP_SILVER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"외로워 봤자 제 지갑 사정보다 외롭겠어요? 양심적으로 좀 비켜요!","JPN":"孤独と言っても私の財布の中身の方がもっと孤独ですよ。いいからどいて！","ENG":"I'm pretty sure my financial state is sadder than whatever you're going through. Come on, move aside if you have a heart.","TWN":"再孤獨也不會比我的錢包更孤獨吧？有良心就讓開點！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GAP_SILVER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"실장님도 한 마디 해주세요! 이대로 돌아가라는 건 완전 막무가내 아니에요?","JPN":"室長からも何か言ってやってください！　このまま帰されるなんて納得できますか？","ENG":"Say something, Chief! It's unfair of them to just tell us to leave!","TWN":"室長你也說句話吧！就這樣讓我們回去完全不合理吧？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"실장님?","JPN":"室長？","ENG":"Chief?","TWN":"室長？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"아빠, 그럼 몇 밤 자면 오는 거야?","JPN":"パパ、じゃあ何回寝たら帰ってくるの？","ENG":"Daddy, how many nights do I have to sleep to see you again?","TWN":"爸爸，這次我要睡幾晚你才會回來呢？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"걱정 마렴, 시그마. 백 밤 자면 돌아올 거란다.","JPN":"大丈夫さ、シグマ。百回寝たら帰ってくるからね。","ENG":"Don't worry, Sigma. It'll only be a hundred nights.","TWN":"西格瑪別擔心，等你睡一百晚後爸爸就回來囉。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"백 밤이나~? 심심하겠다~.","JPN":"百回も～？　つまんない～","ENG":"A hundred nights?! I'm gonna be so bored...!","TWN":"睡一百晚喔～？那我會很無聊欸～"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 모네랑 다른 아이들도 있으니 사이 좋게 지내렴.","JPN":"ハハ、モネや他の子たちもいるから、仲良くしなさい。","ENG":"Haha, you can play with Mone and the other children.","TWN":"哈哈，莫妮和其他小朋友都在，你們要好好相處喔。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"응!","JPN":"わかった！","ENG":"Okay!","TWN":"嗯！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"말 잘 듣고, 착한 아이로 있을게!","JPN":"みんなを困らせないで、いい子にしてるね！","ENG":"I'll be a good girl!","TWN":"我會聽話，做個乖孩子！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"있지. 유피.","JPN":"ねえ、ユピ。","ENG":"Um, Yuppie.","TWN":"好了，悠菲。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L27_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"잔뜩 놀았으니 이제 집에 가도 되지 않을까?","JPN":"もう沢山遊んだから、家に帰らない？","ENG":"Maybe we can just go home now, since we had enough fun.","TWN":"我們玩得差不多了，現在就回家吧？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"네? 갑자기 그게 무슨 소리예요?","JPN":"はい？　いきなりどうしたんですか？","ENG":"What? What are you talking about?","TWN":"呃？你突然在說什麼？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"으으… 하지만 아빠가 안된다고 했는걸.","JPN":"うう……でもパパにダメって言われてるもん。","ENG":"Ngh... But Daddy said no.","TWN":"呃呃……但是爸爸說不行。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"유피랑 크레데레 일은 내가 어떻게든 해볼게. 그러니까…….","JPN":"ユピとクレデレのことは、私がなんとかする。だから……","ENG":"I'll do everything I can for you and Credere. So...","TWN":"悠菲和克蕾妲莉的事我會想辦法的。所以……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"결정이군요. 미래전략실장도 저렇게 말하니 이만 돌아가시죠.","JPN":"決まりましたね。未来戦略室の室長もああやって言っているんですから、もう帰りましょう。","ENG":"Then it's settled. The chief of the Future Strategy Department has spoken. Let us all return.","TWN":"很好。既然未來戰略室長也這麼說了，那我們就回去吧。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"싫~거든요.","JPN":"嫌です～。","ENG":"Noooope.","TWN":"不——要——"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"이렇게까지 했는데 빈손으로 돌아가라니. 사람이 뻔뻔한 것도 정도가 있죠.","JPN":"ここまでやらされたあげく、手ぶらで帰らされるなんて、そんな仕打ち、私は認められません。","ENG":"You expect me to just go back empty-handed? How can you be so shameless?","TWN":"都做到這一步了，還讓我們空手而歸。做人也要有個限度吧。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"뭘 상상하고 있는지는 모르겠지만, 저건 당신이 생각하는 그런 보물이 아닙니다.","JPN":"何を期待しているのかは知りませんが、あそこにあなたが想像しているようなモノは入っていません。","ENG":"I assure you, that's not the kind of treasure you're dreaming of.","TWN":"我可以向你保證，那可不是你想像中的什麼寶藏。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"죄송하지만 못 믿겠네요. 한 번 거짓말한 사람이 두번이라고 못할까.","JPN":"いいえ、そう言われても信じられません。一度嘘をついた人間は、死ぬまで嘘つきのままですから。","ENG":"I'm sorry, but I don't buy that. You're an established liar. I have no reason to believe you.","TWN":"抱歉，我不信。撒過一次謊的人，怎麼可能不會撒第二次呢。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"저게 보물이 아니라면 부사장님은 뭣 때문에 여기 오신 건데요?","JPN":"それにもしそれが本当だとしたら、副社長は何をしにここまで来たんですか？","ENG":"Besides, if that's not treasure, what are you doing here?","TWN":"如果那不是寶物，副總你到這裡來又是為了什麼？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"세상 일이 마음대로 굴러가지는 않는 법이죠. 아이든 어른이든 그건 매한가지입니다.","JPN":"人生は思うようにいかないものです。子どもだろうと大人だろうと、それは同じ。","ENG":"Things don't always go the way you want them to. It is the same for children and adults alike.","TWN":"世上的事不會總是如人所願。不論是孩子還是大人，都是一樣。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L41_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"당장 본인 일부터 돌이켜 보시죠. 매번 마음먹은 대로 일이 풀렸나요?","JPN":"自分の経験をまず振り返ってみてごらんなさい。いつも思い通りになっていまいたか？","ENG":"Look back on what you've been through. Did things always go as you planned?","TWN":"先反省一下你自己的事吧。每次都能稱你的心意嗎？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"윽. 그건…….","JPN":"うっ、それは……","ENG":"Ugh. Well...","TWN":"呃，這個嘛……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"굽힐 줄 아는 것도 용기입니다, 유피 양.","JPN":"たまには意志を曲げる勇気も必要です、ユピさん。","ENG":"Knowing when to give up takes courage, Yuppie.","TWN":"懂得退一步也是一種勇氣，悠菲。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"말뿐인 사람의 최후를 저는 지금껏 여럿 봐왔지요.","JPN":"口先だけの人間の末路を、私は何度も見てきました。","ENG":"I've seen the end of countless individuals who were all talk and no substance.","TWN":"我見過太多次只會說大話的人的下場。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"말밖에 없는데 말싸움 정도는 져주셔야 하는 거 아니에요?","JPN":"勝てる要素が口しかないんだから、そこは負けてくれてもいいじゃないですか。","ENG":"All I have is \\"talk.\\" Don't you think you can let me win this once?","TWN":"真是得理不饒人，至少在口舌之爭上讓讓我吧？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"어떡하지? 실장님은 저런 상태고 이제 도와줄 사람도 없는데.","JPN":"どうしよう？　室長はあの調子だし、もう助けに来てくれる人もいない。","ENG":"What do I do? Chief is acting weird and there's no one to help me anymore.","TWN":"怎麼辦？室長現在那種狀態，已經沒有人能幫忙了。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"이제 정말…","JPN":"もう本当に……","ENG":"Is this really–","TWN":"難道真的要回去……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":" 응?","JPN":" うん？","ENG":" Hmm?","TWN":"嗯？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"이건…….","JPN":"これは……","ENG":"This is...","TWN":"這個是……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"GAP_SILVER_NULL_NULL","text":{"KOREA":"갑자기 땅이 흔들리는데 뭐지? 설마 지진인가?","JPN":"急に地面が揺れ出したが、なんだ？　まさか地震か？","ENG":"The ground is shaking. What's going on? Is this an earthquake?","TWN":"我怎麼感覺地在晃呢？難道是地震來了？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_SILVER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"섬 안 카운터들이 난동을 부린 탓에 차원 계면이 약해진 상태입니다.","JPN":"カウンターたちが島で暴れたせいで、次元界面がもろくなったようです。","ENG":"The dimension surface is unstable because the Counters on the island were causing a ruckus.","TWN":"島上有制裁者鬧事，會導致次元介面變得脆弱。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"설마 아티팩트가 매개체라는 얼토당토 않은 이유로 나타난……","JPN":"まさかアーティファクトが媒体だというとんでもない理由で現れたんじゃ……","ENG":"This can't be something that happened because of an absurd reason like the Artifact being the medium–","TWN":"總不可能是因為人造神器這種奇奇怪怪的原因……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네~!","JPN":"モネ～！","ENG":"Mone!","TWN":"莫妮～！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"…………모네?","JPN":"……モネ？","ENG":"...Mone?","TWN":"……莫妮？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);expo